mapper.select:
SELECT
rc_learn.invitation_table.id, rc_learn.invitation_table.context, rc_learn.invitation_table.coverImgUrl, rc_learn.invitation_table.title, rc_learn.invitation_table.type, rc_learn.invitation_table.likenumber, rc_learn.invitation_table.visitnumber, rc_learn.invitation_table.commentnumber, rc_personal.favorites_invitation_table.userId, rc_learn.invitation_table.state, rc_learn.invitation_table.creat_time
FROM rc_learn.invitation_table JOIN rc_personal.favorites_invitation_table ON rc_personal.favorites_invitation_table.invitationId = rc_learn.invitation_table.id JOIN rc_personal.user_table ON rc_personal.favorites_invitation_table.userId = rc_personal.user_table.id where rc_personal.favorites_invitation_table.favoritesId = #{favoritesId} and rc_personal.favorites_invitation_table.userId = #{currentUserId}
